"use strict";const input=document.querySelector(".input"),button=document.querySelector(".button"),divka=document.querySelector(".div");function numMaker(t){let e=t.split(" "),n=Object.assign({},e);for(let t in n)init(n[t])}function init(t){let e=t.split("-"),n="";for(let t=e[0];t<=e[1];t++)n+=t+";";adder(n.substring(0,n.length-1))}function adder(t){let e=document.createElement("p");e.className="total",e.innerHTML=t,divka.append(e)}button.addEventListener("click",()=>{numMaker(input.value)});